/**
 * Chatwoot webhook: bara inkommande kundmeddelanden (message_type 0).
 * Undvik loop: vårt utgående svar har message_type 1 → ignoreras här.
 */
const root = items[0].json;
const body = root.body !== undefined ? root.body : root;
const msg = body.message || body;
const conv = body.conversation || {};
const acc = body.account || {};

const accountId = acc.id ?? body.account_id;
const conversationId = conv.id ?? body.conversation_id;
const messageType = msg.message_type;
const content = String(msg.content ?? msg.text ?? '').trim();

const isIncoming = messageType === 0 || messageType === 'incoming';

if (!isIncoming) {
  return [{ json: { skip: true, reason: 'not_incoming_or_bot_reply', accountId, conversationId } }];
}
if (!content) {
  return [{ json: { skip: true, reason: 'empty_content', accountId, conversationId } }];
}
if (accountId == null || conversationId == null) {
  return [{ json: { skip: true, reason: 'missing_ids', accountId, conversationId } }];
}

return [{ json: { skip: false, message: content, accountId, conversationId } }];

const q = $('Tolka Chatwoot (guard)').first().json.message || '';
const flow = items[0].json;
const hadHttpError = Boolean(flow.error);
const raw = hadHttpError ? '' : String(flow.text ?? flow.data?.text ?? flow.output ?? '');
const cleaned = raw.trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
let parsed = null;
try {
  parsed = cleaned ? JSON.parse(cleaned) : null;
} catch {}
const lower = String(q).toLowerCase();
const fallbackCategory = /tidsmaskin|paradox/.test(lower)
  ? 'time_machine_issue'
  : /fortfarande d[oö]d|r[oö]r sig inte|[aå]teruppliv/.test(lower)
    ? 'resurrection_support'
    : /leverans|frakt|saknas|fel/.test(lower)
      ? 'shipping_or_subscription'
      : 'general_question';
const reply = parsed?.reply || raw || 'Tyvärr kunde jag inte generera svar just nu. Kontrollera Flowise eller OpenAI.';
const escalate = typeof parsed?.escalate === 'boolean' ? parsed.escalate : hadHttpError || reply.length < 18;
const category = parsed?.category || fallbackCategory;
const reason = parsed?.reason || (escalate ? 'Borde troligen granskas av människa.' : 'Kan hanteras i chatten.');
const accountId = $('Tolka Chatwoot (guard)').first().json.accountId;
const conversationId = $('Tolka Chatwoot (guard)').first().json.conversationId;
items[0].json = { reply, escalate, category, reason, accountId, conversationId };
return items;
